#include <stdio.h>

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}

int main() {
    int num1 = 48, num2 = 18;

    printf("Sayilar: %d ve %d\n", num1, num2);
    printf("EBOB (GCD): %d\n", gcd(num1, num2));
    printf("EKOK (LCM): %d\n", lcm(num1, num2));

    // Birden fazla cift icin tablo
    printf("\nFarkli sayi ciftleri:\n");
    int pairs[4][2] = {{12, 18}, {7, 13}, {100, 75}, {24, 36}};

    for (int i = 0; i < 4; i++) {
        int a = pairs[i][0];
        int b = pairs[i][1];
        printf("GCD(%d,%d) = %d, LCM(%d,%d) = %d\n", a, b, gcd(a, b), a, b, lcm(a, b));
    }

    return 0;
}
